/* Dashboard Layout */
.dashboard-layout {
  display: flex;
  min-height: 100vh;
}

/* Sidebar */
.sidebar {
  width: 260px;
  background: var(--bg-secondary);
  border-right: 1px solid var(--border-color);
  display: flex;
  flex-direction: column;
  padding: 24px;
  position: fixed;
  top: 0;
  left: 0;
  height: 100vh;
  z-index: 50;
}

.sidebar .logo {
  margin-bottom: 40px;
}

.sidebar-nav {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.nav-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  border-radius: var(--radius-md);
  font-size: 15px;
  color: var(--text-secondary);
  transition: all 0.2s;
}

.nav-item:hover {
  background: var(--bg-elevated);
  color: var(--text-primary);
}

.nav-item.active {
  background: rgba(16, 185, 129, 0.1);
  color: var(--accent-primary);
}

.nav-icon {
  font-size: 18px;
}

.sidebar-footer {
  padding-top: 24px;
  border-top: 1px solid var(--border-color);
}

.user-info {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 16px;
}

.user-avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--accent-gradient);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 600;
  font-size: 16px;
  color: #000;
}

.user-details {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.user-name {
  font-weight: 500;
  font-size: 14px;
}

.user-plan {
  font-size: 12px;
  color: var(--text-muted);
}

.user-plan.pro {
  color: var(--accent-primary);
}

/* Main Content */
.main-content {
  flex: 1;
  margin-left: 260px;
  padding: 32px 40px;
  max-width: 1200px;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 40px;
}

.page-header h1 {
  font-family: var(--font-display);
  font-size: 28px;
  font-weight: 700;
  margin-bottom: 4px;
}

.page-header p {
  color: var(--text-secondary);
  font-size: 15px;
}

/* Stats Grid */
.stats-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
  margin-bottom: 40px;
}

.stat-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 24px;
  display: flex;
  align-items: center;
  gap: 16px;
}

.stat-card.highlight {
  background: rgba(16, 185, 129, 0.05);
  border-color: rgba(16, 185, 129, 0.2);
}

.stat-icon {
  font-size: 32px;
}

.stat-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-card .stat-value {
  font-family: var(--font-display);
  font-size: 28px;
  font-weight: 700;
}

.stat-card.highlight .stat-value {
  color: var(--accent-primary);
}

.stat-card .stat-label {
  font-size: 13px;
  color: var(--text-muted);
}

/* Sections */
.section {
  margin-bottom: 40px;
}

.section h2 {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 600;
  margin-bottom: 20px;
}

.section .section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.section .section-header h2 {
  margin-bottom: 0;
}

/* Action Grid */
.action-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
}

.action-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 24px;
  transition: all 0.2s;
}

.action-card:hover {
  border-color: var(--accent-primary);
  transform: translateY(-2px);
  box-shadow: var(--shadow-glow);
}

.action-icon {
  font-size: 32px;
  margin-bottom: 16px;
}

.action-card h3 {
  font-family: var(--font-display);
  font-size: 16px;
  font-weight: 600;
  margin-bottom: 8px;
}

.action-card p {
  font-size: 13px;
  color: var(--text-muted);
}

/* Interview List */
.interview-list {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.interview-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 24px;
  border-bottom: 1px solid var(--border-color);
}

.interview-item:last-child {
  border-bottom: none;
}

.interview-info {
  display: flex;
  align-items: center;
  gap: 16px;
}

.interview-type {
  padding: 6px 12px;
  background: var(--bg-elevated);
  border-radius: var(--radius-full);
  font-size: 13px;
  font-weight: 500;
  text-transform: capitalize;
}

.interview-date {
  font-size: 14px;
  color: var(--text-muted);
}

.interview-score .score {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 600;
  color: var(--accent-primary);
}

.interview-score .pending {
  font-size: 14px;
  color: var(--text-muted);
}

/* Empty State */
.empty-state {
  padding: 60px 40px;
  text-align: center;
}

.empty-state p {
  color: var(--text-secondary);
  margin-bottom: 20px;
}

/* Loading State */
.loading-state {
  padding: 60px 40px;
  text-align: center;
}

.spinner {
  width: 32px;
  height: 32px;
  border: 3px solid var(--border-color);
  border-top-color: var(--accent-primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 0 auto 16px;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* Upgrade Banner */
.upgrade-banner {
  background: var(--bg-card);
  border: 1px solid var(--accent-primary);
  border-radius: var(--radius-lg);
  padding: 32px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  box-shadow: var(--shadow-glow);
}

.upgrade-content h3 {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 600;
  margin-bottom: 8px;
}

.upgrade-content p {
  color: var(--text-secondary);
  font-size: 15px;
}

/* Button sizes */
.btn-sm {
  padding: 8px 16px;
  font-size: 13px;
}

/* Mobile Sidebar Toggle */
.mobile-sidebar-toggle {
  display: none;
  position: fixed;
  top: 16px;
  left: 16px;
  z-index: 100;
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 8px;
  padding: 10px 14px;
  color: var(--text-primary);
  cursor: pointer;
  font-size: 20px;
  min-width: 44px;
  min-height: 44px;
  box-shadow: var(--shadow-md);
}

.mobile-sidebar-toggle:hover {
  background: var(--bg-elevated);
  border-color: var(--accent-primary);
}

.sidebar.mobile-open {
  transform: translateX(0);
}

.sidebar-overlay {
  display: none;
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  z-index: 49;
}

.sidebar-overlay.active {
  display: block;
}

/* Responsive */
@media (max-width: 1200px) {
  .stats-grid,
  .action-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 1024px) {
  .main-content {
    padding: 24px 32px;
  }

  .page-header {
    margin-bottom: 32px;
  }

  .page-header h1 {
    font-size: 24px;
  }

  .stats-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 16px;
  }

  .action-grid {
    grid-template-columns: repeat(3, 1fr);
  }
}

@media (max-width: 768px) {
  .mobile-sidebar-toggle {
    display: block;
  }

  .sidebar {
    transform: translateX(-100%);
    transition: transform 0.3s ease;
    z-index: 50;
  }

  .main-content {
    margin-left: 0;
    padding: 72px 20px 24px;
  }

  .stats-grid {
    grid-template-columns: 1fr;
    gap: 12px;
  }

  .stat-card {
    padding: 20px;
  }

  .stat-card .stat-value {
    font-size: 24px;
  }

  .action-grid {
    grid-template-columns: 1fr;
    gap: 12px;
  }

  .action-card {
    padding: 20px;
  }

  .upgrade-banner {
    flex-direction: column;
    text-align: center;
    gap: 20px;
    padding: 24px;
  }

  .interview-item {
    flex-direction: column;
    align-items: flex-start;
    gap: 12px;
    padding: 16px 20px;
  }

  .interview-info {
    flex-direction: column;
    align-items: flex-start;
    gap: 8px;
    width: 100%;
  }

  .page-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 16px;
  }

  .page-header h1 {
    font-size: 22px;
  }
}

@media (max-width: 480px) {
  .main-content {
    padding: 64px 16px 20px;
  }

  .page-header h1 {
    font-size: 20px;
  }

  .stat-card {
    padding: 16px;
  }

  .action-card {
    padding: 16px;
  }

  .upgrade-banner {
    padding: 20px;
  }

  .section h2 {
    font-size: 18px;
  }
}

/* User Dropdown Menu */
.user-dropdown-container {
  position: relative;
}

.user-menu-toggle {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 0;
  background: none;
  border: none;
  cursor: pointer;
  color: inherit;
  transition: all 0.2s;
}

.user-menu-toggle:hover {
  opacity: 0.8;
}

.user-dropdown-menu {
  position: absolute;
  bottom: 100%;
  left: -16px;
  right: -16px;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  margin-bottom: 8px;
  box-shadow: 0 -8px 32px rgba(0, 0, 0, 0.3);
  z-index: 1000;
  min-width: 220px;
  overflow: hidden;
  display: none;
}

.user-dropdown-menu.active {
  display: block;
}

.dropdown-header {
  padding: 16px;
  border-bottom: 1px solid var(--border-color);
  background: var(--bg-elevated);
}

.dropdown-user-name {
  display: block;
  font-weight: 600;
  font-size: 14px;
  margin-bottom: 2px;
}

.dropdown-user-email {
  display: block;
  font-size: 12px;
  color: var(--text-muted);
}

.dropdown-items {
  display: flex;
  flex-direction: column;
  padding: 8px;
}

.dropdown-item {
  display: flex;
  align-items: center;
  padding: 10px 12px;
  font-size: 14px;
  color: var(--text-primary);
  text-decoration: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all 0.2s;
  background: none;
  border: none;
  width: 100%;
  text-align: left;
}

.dropdown-item:hover {
  background: var(--bg-elevated);
}

.dropdown-item.danger {
  color: #ef4444;
}

.dropdown-item.danger:hover {
  background: rgba(239, 68, 68, 0.1);
}

.dropdown-divider {
  height: 1px;
  background: var(--border-color);
  margin: 4px 0;
}

