     1→// Shared auth utilities for pages that don't include main.js
     2→const AUTH_TOKEN_KEY = 'rekrutai_token';
     3→const AUTH_REFRESH_KEY = 'rekrutai_refresh';
     4→
     5→function getAuthToken() {
     6→  return localStorage.getItem(AUTH_TOKEN_KEY);
     7→}
     8→
     9→function getAuthHeaders() {
    10→  const token = getAuthToken();
    11→  return token ? { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' } : {};
    12→}
    13→
    14→// checkAuth that returns user data (matches main.js behavior)
    15→let _authPromise = null;
    16→async function checkAuth() {
    17→  if (_authPromise) return _authPromise;
    18→
    19→  _authPromise = (async () => {
    20→    const token = getAuthToken();
    21→    if (!token) {
    22→      window.location.href = '/login.html';
    23→      return null;
    24→    }
    25→
    26→    try {
    27→      const response = await fetch('/api/auth/me', {
    28→        headers: { 'Authorization': `Bearer ${token}` }
    29→      });
    30→
    31→      if (response.ok) {
    32→        const data = await response.json();
    33→        return data.user || data;
    34→      }
    35→
    36→      // Token expired, try refresh
    37→      if (response.status === 401) {
    38→        const refreshToken = localStorage.getItem(AUTH_REFRESH_KEY);
    39→        if (refreshToken) {
    40→          try {
    41→            const refreshRes = await fetch('/api/auth/refresh', {
    42→              method: 'POST',
    43→              headers: { 'Content-Type': 'application/json' },
    44→              body: JSON.stringify({ refreshToken })
    45→            });
    46→
    47→            if (refreshRes.ok) {
    48→              const refreshData = await refreshRes.json();
    49→              localStorage.setItem(AUTH_TOKEN_KEY, refreshData.accessToken || refreshData.token);
    50→              if (refreshData.refreshToken) {
    51→                localStorage.setItem(AUTH_REFRESH_KEY, refreshData.refreshToken);
    52→              }
    53→              // Retry with new token
    54→              const retryRes = await fetch('/api/auth/me', {
    55→                headers: { 'Authorization': `Bearer ${refreshData.accessToken || refreshData.token}` }
    56→              });
    57→              if (retryRes.ok) {
    58→                const data = await retryRes.json();
    59→                return data.user || data;
    60→              }
    61→            }
    62→          } catch (refreshErr) {
    63→            console.error('Token refresh failed:', refreshErr);
    64→          }
    65→        }
    66→
    67→        // Refresh failed, redirect to login
    68→        localStorage.removeItem(AUTH_TOKEN_KEY);
    69→        localStorage.removeItem(AUTH_REFRESH_KEY);
    70→        window.location.href = '/login.html';
    71→        return null;
    72→      }
    73→
    74→      return null;
    75→    } catch (err) {
    76→      console.error('Auth check failed:', err);
    77→      return null;
    78→    } finally {
    79→      _authPromise = null;
    80→    }
    81→  })();
    82→
    83→  return _authPromise;
    84→}
    85→
    86→// Alias for backward compat
    87→async function checkAuthAndRedirect() {
