input.new_string:
// Modal close on click outside
document.getElementById('modal').addEventListener('click', (e) => {
  if (e.target.id === 'modal') closeModal();
});

// Escape key closes modals
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    // Close doc preview first, then main modal
    const docPreview = document.querySelector('.doc-preview-overlay');
    if (docPreview) {
      docPreview.remove();
      return;
    }
    const modal = document.getElementById('modal');
    if (modal && modal.classList.contains('active')) {
      closeModal();
    }
  }
});

// Mobile sidebar toggle
function setupMobileSidebar() {
  const sidebar = document.getElementById('sidebar');
  const toggle = document.getElementById('mobile-sidebar-toggle');
  const overlay = document.getElementById('sidebar-overlay');
  if (!sidebar || !toggle || !overlay) return;

  toggle.addEventListener('click', () => {
    sidebar.classList.toggle('mobile-open');
    overlay.classList.toggle('active');
    toggle.innerHTML = sidebar.classList.contains('mobile-open') ? '✕' : '☰';
  });

  overlay.addEventListener('click', () => {
    sidebar.classList.remove('mobile-open');
    overlay.classList.remove('active');
    toggle.innerHTML = '☰';
  });

  // Close sidebar when clicking nav items on mobile
  sidebar.querySelectorAll('.nav-item').forEach(item => {
    item.addEventListener('click', () => {
      if (window.innerWidth <= 768) {
        sidebar.classList.remove('mobile-open');
        overlay.classList.remove('active');
        toggle.innerHTML = '☰';
      }
    });
  });
}

// Initialize
document.addEventListener('DOMContentLoaded', () => {
  loadOnboardingDocuments();
  setupUserMenu();
  setupMobileSidebar();
  // Auto-refresh every 30 seconds for real-time updates
  setInterval(loadOnboardingDocuments, 30000);
});

