   587→  <script>
   588→    const BACKEND_URL = '/api';
   589→    let currentCandidateId = null;
   590→
   591→    async function loadOnboardingDocuments() {
   592→      try {
   593→        const response = await fetch(`${BACKEND_URL}/onboarding/recruiter/summary`, {
   594→          headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` }
   595→        });
   596→
   597→        if (!response.ok) throw new Error('Failed to load documents');
   598→
   599→        const data = await response.json();
   600→        displayCandidates(data);
   601→      } catch (error) {
   602→        console.error('Error:', error);
   603→        document.getElementById('empty-state').style.display = 'block';
   604→        document.getElementById('candidates-container').innerHTML = '';
   605→      }
   606→    }
   607→
   608→    function displayCandidates(candidates) {
   609→      const container = document.getElementById('candidates-container');
   610→
   611→      if (!candidates || candidates.length === 0) {
   612→        document.getElementById('empty-state').style.display = 'block';
   613→        container.innerHTML = '';
   614→        return;
   615→      }
   616→
   617→      document.getElementById('empty-state').style.display = 'none';
   618→
   619→      container.innerHTML = candidates.map(candidate => {
   620→        const total = parseInt(candidate.total_documents) || 0;
   621→        const signed = parseInt(candidate.signed_documents) || 0;
   622→        const pct = total > 0 ? Math.round((signed / total) * 100) : 0;
   623→        const barColor = pct === 100 ? '#10b981' : pct > 0 ? '#f59e0b' : '#e5e7eb';
   624→
   625→        return `
   626→        <div class="candidate-card" onclick="viewCandidateDetails(${candidate.candidate_id})">
   627→          <div class="candidate-header">
   628→            <div class="candidate-info">
   629→              <h3>${escapeHtml(candidate.candidate_name)}</h3>
   630→              <div class="candidate-email">${escapeHtml(candidate.candidate_email)}</div>
   631→              ${candidate.job_title ? `<div class="candidate-job">${escapeHtml(candidate.job_title)}</div>` : ''}
   632→            </div>
   633→            <span class="onboarding-status status-${candidate.onboarding_status || 'pending'}">
   634→              ${formatStatus(candidate.onboarding_status)}
   635→            </span>
   636→          </div>
   637→
   638→          <!-- Progress bar -->
   639→          <div style="margin-top: 12px;">
   640→            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px;">
   641→              <span style="font-size: 12px; color: var(--text-muted);">Document Progress</span>
   642→              <span style="font-size: 12px; font-weight: 600; color: ${barColor};">${pct}%</span>
   643→            </div>
   644→            <div style="height: 6px; background: var(--border-color); border-radius: 3px; overflow: hidden;">
   645→              <div style="height: 100%; width: ${pct}%; background: ${barColor}; border-radius: 3px; transition: width 0.3s;"></div>
   646→            </div>
   647→          </div>
   648→
   649→          <div class="docs-summary">
   650→            <div class="summary-item">
   651→              <strong>${signed}</strong>
   652→              <span>Signed</span>
   653→            </div>
   654→            <div class="summary-item">
   655→              <strong>${total}</strong>
   656→              <span>Total Docs</span>
   657→            </div>
   658→          </div>
   659→
   660→          ${candidate.due_date ? `
   661→            <div style="margin-top: 12px; padding-top: 12px; border-top: 1px solid var(--border-color); font-size: 12px; color: var(--text-muted);">
   662→              Due: ${formatDate(candidate.due_date)}
   663→            </div>
   664→          ` : ''}
   665→
   666→          <div style="margin-top: 12px; text-align: right;">
   667→            <a class="view-link" onclick="event.stopPropagation(); viewCandidateDetails(${candidate.candidate_id})">View Details →</a>
   668→          </div>
   669→        </div>
   670→      `}).join('');
   671→    }
   672→
   673→    async function viewCandidateDetails(candidateId) {
   674→      currentCandidateId = candidateId;
   675→
   676→      try {
   677→        // Load candidate details and documents
   678→        const response = await fetch(
   679→          `${BACKEND_URL}/onboarding/recruiter/candidate/${candidateId}/documents`,
   680→          { headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` } }
   681→        );
   682→
   683→        if (!response.ok) throw new Error('Failed to load documents');
   684→
   685→        const documents = await response.json();
   686→        const candidateData = documents[0];
   687→
   688→        // Update modal header
   689→        document.getElementById('modal-candidate-name').textContent = candidateData.candidate_name;
   690→        document.getElementById('modal-candidate-email').textContent = candidateData.candidate_email;
   691→
   692→        // Update details
   693→        document.getElementById('modal-job').textContent = candidateData.job_title || '—';
   694→        document.getElementById('modal-start-date').textContent = candidateData.start_date ? formatDate(candidateData.start_date) : '—';
   695→
   696→        // Display documents
   697→        const docsContainer = document.getElementById('modal-documents');
   698→        if (documents.length === 0) {
   699→          docsContainer.innerHTML = '<p style="color: var(--text-muted);">No documents yet</p>';
   700→        } else {
   701→          docsContainer.innerHTML = documents.map(doc => `
   702→            <div class="doc-item" style="border-left-color: ${doc.signed_at ? '#10b981' : doc.uploaded_at ? '#3b82f6' : '#e5e7eb'};">
   703→              <div class="doc-item-header">
   704→                <span class="doc-item-type">${escapeHtml(doc.document_type)}</span>
   705→                <span class="doc-item-date">${formatDate(doc.created_at)}</span>
   706→              </div>
   707→              <div style="display: flex; align-items: center; justify-content: space-between; margin-top: 8px; flex-wrap: wrap; gap: 8px;">
   708→                <div>
   709→                  ${doc.signed_at ? `
   710→                    <span class="document-status status-signed">✓ Signed ${formatDate(doc.signed_at)}</span>
   711→                  ` : doc.uploaded_at ? `
   712→                    <span class="document-status status-uploaded">✓ Generated</span>
   713→                  ` : `
   714→                    <span class="document-status status-pending-doc">Pending</span>
   715→                  `}
   716→                </div>
   717→                <div class="doc-actions-row" style="display: flex; gap: 8px; flex-wrap: wrap;">
   718→                  ${doc.document_content ? `<a class="view-link" onclick="viewDocContent(${doc.id}, '${escapeHtml(doc.document_type)}')">View Details</a>` : ''}
   719→                  ${doc.document_content ? `<a class="view-link" href="/api/onboarding/recruiter/document/${doc.id}/download" target="_blank" style="color: #10b981;">⬇ Download</a>` : ''}
   720→                  ${doc.document_url ? `<a href="${doc.document_url}" target="_blank" class="view-link">Open File</a>` : ''}
   721→                </div>
   722→              </div>
   723→              ${doc.content_summary ? `<p style="font-size: 12px; color: var(--text-muted); margin-top: 8px;">${escapeHtml(doc.content_summary)}</p>` : ''}
   724→              ${doc.signer_ip ? `<p style="font-size: 11px; color: var(--text-muted); margin-top: 4px;">Audit: IP ${escapeHtml(doc.signer_ip)} | ${formatDate(doc.signed_at)}</p>` : ''}
   725→            </div>
   726→          `).join('');
   727→
   728→          // Store docs for preview
   729→          window._currentDocs = documents;
   730→
   731→          // Show download all button if docs have content
   732→          const hasContent = documents.some(d => d.document_content);
   733→          const dlBtn = document.getElementById('download-all-btn');
   734→          if (dlBtn) dlBtn.style.display = hasContent ? 'inline-block' : 'none';
   735→        }
   736→
   737→        // Show modal
   738→        document.getElementById('modal').classList.add('active');
   739→      } catch (error) {
   740→        console.error('Error:', error);
   741→        alert('Failed to load candidate details');
   742→      }
   743→    }
   744→
   745→    function closeModal() {
   746→      document.getElementById('modal').classList.remove('active');
   747→      currentCandidateId = null;
   748→    }
   749→
   750→    function formatStatus(status) {
   751→      const statuses = {
   752→        'pending': 'Pending',
   753→        'in_progress': 'In Progress',
   754→        'completed': 'Completed'
   755→      };
   756→      return statuses[status] || 'Unknown';
   757→    }
   758→
   759→    function formatDate(dateString) {
   760→      if (!dateString) return '—';
   761→      const date = new Date(dateString);
   762→      return date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
   763→    }
   764→
   765→    function escapeHtml(text) {
   766→      if (!text) return '';
   767→      const map = {
   768→        '&': '&amp;',
   769→        '<': '&lt;',
   770→        '>': '&gt;',
   771→        '"': '&quot;',
   772→        "'": '&#039;'
   773→      };
   774→      return text.replace(/[&<>"']/g, m => map[m]);
   775→    }
   776→
   777→    function viewDocContent(docId, docType) {
   778→      const doc = (window._currentDocs || []).find(d => d.id === docId);
   779→      if (!doc || !doc.document_content) return;
   780→
   781→      // Remove any existing doc preview overlay first (prevent stacking)
   782→      const existing = document.querySelector('.doc-preview-overlay');
   783→      if (existing) existing.remove();
   784→
   785→      const content = typeof doc.document_content === 'string' ? JSON.parse(doc.document_content) : doc.document_content;
   786→      let bodyHtml = '';
   787→
   788→      if (content.form_type === 'I-9') {
   789→        bodyHtml = `
   790→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Employment Eligibility Verification</p>
   791→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   792→          <p><strong>DOB:</strong> ${content.date_of_birth ? new Date(content.date_of_birth).toLocaleDateString() : ''}</p>
   793→          <p><strong>Address:</strong> ${escapeHtml(content.address || '')}, ${escapeHtml(content.city || '')}, ${escapeHtml(content.state || '')} ${escapeHtml(content.zip || '')}</p>
   794→          <p><strong>SSN:</strong> ${content.ssn_last_four}</p>
   795→          <p><strong>Employer:</strong> ${escapeHtml(content.company || '')}</p>
   796→        `;
   797→      } else if (content.form_type === 'W-4') {
   798→        bodyHtml = `
   799→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">W-4 Tax Withholding</p>
   800→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   801→          <p><strong>Address:</strong> ${escapeHtml(content.city_state_zip || '')}</p>
   802→          <p><strong>Filing Status:</strong> ${escapeHtml(content.filing_status || 'Single')}</p>
   803→        `;
   804→      } else if (content.form_type === 'Direct Deposit Authorization') {
   805→        bodyHtml = `
   806→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Direct Deposit</p>
   807→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   808→          <p><strong>Bank:</strong> ${escapeHtml(content.bank_name || '')}</p>
   809→          <p><strong>Account Type:</strong> ${escapeHtml(content.account_type || '')}</p>
   810→        `;
   811→      } else {
   812→        bodyHtml = `<pre style="white-space: pre-wrap; font-size: 12px;">${JSON.stringify(content, null, 2)}</pre>`;
   813→      }
   814→
   815→      if (doc.signed_at) {
   816→        bodyHtml += `<hr style="margin: 12px 0;"><p style="color: #10b981; font-weight: 600;">✓ Signed on ${new Date(doc.signed_at).toLocaleString()}</p>`;
   817→        if (doc.signer_ip) bodyHtml += `<p style="font-size: 11px; color: #888;">IP: ${escapeHtml(doc.signer_ip)}</p>`;
   818→      }
   819→
   820→      const overlay = document.createElement('div');
   821→      overlay.className = 'doc-preview-overlay';
   822→      overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
   823→      overlay.innerHTML = `
   824→        <div class="doc-preview-content">
   825→          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;gap:12px;">
   826→            <h3 style="font-size:16px;font-weight:600;word-break:break-word;">${escapeHtml(docType)}</h3>
   827→            <button onclick="document.querySelector('.doc-preview-overlay').remove()" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-muted);flex-shrink:0;padding:4px;">✕</button>
   828→          </div>
   829→          <div style="font-size:13px;line-height:1.7;">${bodyHtml}</div>
   830→        </div>
   831→      `;
   832→      document.body.appendChild(overlay);
   833→    }
   834→
   835→    function downloadAllDocs() {
   836→      const docs = window._currentDocs || [];
   837→      docs.forEach((doc, i) => {
   838→        if (doc.document_content) {
   839→          setTimeout(() => {
   840→            window.open(`/api/onboarding/recruiter/document/${doc.id}/download`, '_blank');
   841→          }, i * 500);
   842→        }
   843→      });
   844→    }
   845→
   846→    // Modal close on click outside
   847→    document.getElementById('modal').addEventListener('click', (e) => {
   848→      if (e.target.id === 'modal') closeModal();
   849→    });
   850→
   851→    // Escape key closes modals
   852→    document.addEventListener('keydown', (e) => {
   853→      if (e.key === 'Escape') {
   854→        // Close doc preview first, then main modal
   855→        const docPreview = document.querySelector('.doc-preview-overlay');
   856→        if (docPreview) {
   857→          docPreview.remove();
   858→          return;
   859→        }
   860→        const modal = document.getElementById('modal');
   861→        if (modal && modal.classList.contains('active')) {
   862→          closeModal();
   863→        }
   864→      }
   865→    });
   866→
   867→    // Mobile sidebar toggle
   868→    function setupMobileSidebar() {
   869→      const sidebar = document.getElementById('sidebar');
   870→      const toggle = document.getElementById('mobile-sidebar-toggle');
   871→      const overlay = document.getElementById('sidebar-overlay');
   872→      if (!sidebar || !toggle || !overlay) return;
   873→
   874→      toggle.addEventListener('click', () => {
   875→        sidebar.classList.toggle('mobile-open');
   876→        overlay.classList.toggle('active');
   877→        toggle.innerHTML = sidebar.classList.contains('mobile-open') ? '✕' : '☰';
   878→      });
   879→
   880→      overlay.addEventListener('click', () => {
   881→        sidebar.classList.remove('mobile-open');
   882→        overlay.classList.remove('active');
   883→        toggle.innerHTML = '☰';
   884→      });
   885→
   886→      // Close sidebar when clicking nav items on mobile
   887→      sidebar.querySelectorAll('.nav-item').forEach(item => {
   888→        item.addEventListener('click', () => {
   889→          if (window.innerWidth <= 768) {
   890→            sidebar.classList.remove('mobile-open');
   891→            overlay.classList.remove('active');
   892→            toggle.innerHTML = '☰';
   893→          }
   894→        });
   895→      });
   896→    }
   897→
   898→    // Initialize
   899→    document.addEventListener('DOMContentLoaded', () => {
   900→      loadOnboardingDocuments();
   901→      setupUserMenu();
   902→      setupMobileSidebar();
   903→      // Auto-refresh every 30 seconds for real-time updates
   904→      setInterval(loadOnboardingDocuments, 30000);
   905→    });
   906→  </script>
